from langchain.chains import RetrievalQA
from langchain.schema import BaseRetriever

def detect_rag_hallucination(chain_output, retriever: BaseRetriever):
    response = chain_output['result']
    # Extract cited doc ids from response
    cited_docs = extract_cited_docs(response)  # Custom regex parser

    query = chain_output['query']
    retrieved_docs = retriever.get_relevant_documents(query)
    doc_contents = {doc.metadata.get('id', i): doc.page_content for i, doc in enumerate(retrieved_docs)}

    for cited_id in cited_docs:
        if cited_id not in doc_contents:
            return {'hallucination': True, 'missing_doc': cited_id}
    return {'hallucination': False}

from langchain.agents import AgentExecutor
from collections import defaultdict

def detect_tool_loops(executor_output):
    steps = executor_output.get('intermediate_steps', [])
    tool_calls = defaultdict(list)

    for action, _ in steps:
        tool_name = action.tool
        tool_args = str(action.tool_input)
        tool_calls[tool_name].append(tool_args)

        # Detect 3+ identical calls
        if len(tool_calls[tool_name]) >= 3 and len(set(tool_calls[tool_name][-3:])) == 1:
            return {'loop_detected': True, 'tool': tool_name, 'count': len(tool_calls[tool_name])}

    return {'loop_detected': False}

from langchain.tools import BaseTool
import json

def validate_tool_schema(tool_call: dict, tool: BaseTool):
    try:
        parsed_args = json.loads(tool_call['args'])
        tool._run(parsed_args)  # Schema validation happens here
        return {'valid': True}
    except Exception as e:
        return {'valid': False, 'error': str(e), 'hallucination': 'malformed_args'}

