from langchain.agents import AgentExecutor
from functools import lru_cache

class LoopProofAgentExecutor(AgentExecutor):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.recent_calls = []

    def _should_continue(self, observation, *args, **kwargs):
        action = super()._should_continue(observation, *args, **kwargs)

        # Check for loop
        call_signature = f"{action.tool}_{str(action.tool_input)}"
        if call_signature in self.recent_calls[-3:]:
            return AgentFinish({'output': 'Loop detected. Final answer based on available info.'}, log='Loop terminated')

        self.recent_calls.append(call_signature)
        if len(self.recent_calls) > 10:
            self.recent_calls.pop(0)

        return action
